+import { describe, it, expect, beforeEach } from 'vitest';
+import { PreferencesService } from '../../src/services/preferences.service.js';
+import { EventBus } from '../../src/events/event-bus.js';
+import {
+  NotificationService,
+  resetNotificationIdCounter,
+} from '../../src/services/notification.service.js';
+import type { OrderCreatedEvent, UserCreatedEvent } from '../../src/events/event-types.js';
+
+describe('PreferencesService', () => {
+  let service: PreferencesService;
+
+  beforeEach(() => {
+    service = new PreferencesService();
+  });
+
+  describe('getPreferences', () => {
+    it('should return default preferences for unknown user', () => {
+      const prefs = service.getPreferences('user-1');
+      expect(prefs.userId).toBe('user-1');
+      expect(prefs.emailEnabled).toBe(true);
+      expect(prefs.categorySubscriptions).toEqual({});
+      expect(prefs.emailFrequency).toBe('immediate');
+      expect(prefs.quietHours).toBeUndefined();
+    });
+
+    it('should return stored preferences for known user', () => {
+      service.updatePreferences('user-1', { emailEnabled: false });
+      const prefs = service.getPreferences('user-1');
+      expect(prefs.emailEnabled).toBe(false);
+    });
+  });
+
+  describe('updatePreferences', () => {
+    it('should update emailEnabled', () => {
+      const prefs = service.updatePreferences('user-1', { emailEnabled: false });
+      expect(prefs.emailEnabled).toBe(false);
+      expect(prefs.emailFrequency).toBe('immediate'); // other defaults preserved
+    });
+
+    it('should update emailFrequency', () => {
+      const prefs = service.updatePreferences('user-1', { emailFrequency: 'daily-digest' });
+      expect(prefs.emailFrequency).toBe('daily-digest');
+    });
+
+    it('should merge category subscriptions', () => {
+      service.updatePreferences('user-1', {
+        categorySubscriptions: { 'order-confirmation': false },
+      });
+      service.updatePreferences('user-1', {
+        categorySubscriptions: { 'order-status-update': false },
+      });
+      const prefs = service.getPreferences('user-1');
+      expect(prefs.categorySubscriptions['order-confirmation']).toBe(false);
+      expect(prefs.categorySubscriptions['order-status-update']).toBe(false);
+    });
+
+    it('should set quiet hours', () => {
+      const prefs = service.updatePreferences('user-1', {
+        quietHours: { start: 22, end: 7 },
+      });
+      expect(prefs.quietHours).toEqual({ start: 22, end: 7 });
+    });
+
+    it('should clear quiet hours when set to null', () => {
+      service.updatePreferences('user-1', { quietHours: { start: 22, end: 7 } });
+      const prefs = service.updatePreferences('user-1', { quietHours: null });
+      expect(prefs.quietHours).toBeUndefined();
+    });
+
+    it('should update the updatedAt timestamp', () => {
+      const before = new Date();
+      const prefs = service.updatePreferences('user-1', { emailEnabled: false });
+      expect(prefs.updatedAt.getTime()).toBeGreaterThanOrEqual(before.getTime());
+    });
+  });
+
+  describe('deletePreferences', () => {
+    it('should return true when preferences existed', () => {
+      service.updatePreferences('user-1', { emailEnabled: false });
+      expect(service.deletePreferences('user-1')).toBe(true);
+    });
+
+    it('should return false when no preferences existed', () => {
+      expect(service.deletePreferences('user-999')).toBe(false);
+    });
+
+    it('should revert to defaults after deletion', () => {
+      service.updatePreferences('user-1', { emailEnabled: false });
+      service.deletePreferences('user-1');
+      const prefs = service.getPreferences('user-1');
+      expect(prefs.emailEnabled).toBe(true);
+    });
+  });
+
+  describe('shouldSendNotification', () => {
+    it('should allow notification with default preferences', () => {
+      expect(service.shouldSendNotification('user-1', 'order-confirmation', 'email')).toBe(true);
+    });
+
+    it('should block notification when email is disabled', () => {
+      service.updatePreferences('user-1', { emailEnabled: false });
+      expect(service.shouldSendNotification('user-1', 'order-confirmation', 'email')).toBe(false);
+    });
+
+    it('should block notification for unsubscribed category', () => {
+      service.updatePreferences('user-1', {
+        categorySubscriptions: { 'order-status-update': false },
+      });
+      expect(service.shouldSendNotification('user-1', 'order-status-update', 'email')).toBe(false);
+    });
+
+    it('should allow notification for subscribed category', () => {
+      service.updatePreferences('user-1', {
+        categorySubscriptions: { 'order-confirmation': true },
+      });
+      expect(service.shouldSendNotification('user-1', 'order-confirmation', 'email')).toBe(true);
+    });
+
+    it('should allow notification for categories not explicitly set', () => {
+      service.updatePreferences('user-1', {
+        categorySubscriptions: { 'order-confirmation': false },
+      });
+      // user-welcome is not in subscriptions, should default to enabled
+      expect(service.shouldSendNotification('user-1', 'user-welcome', 'email')).toBe(true);
+    });
+
+    it('should block notification when frequency is not immediate', () => {
+      service.updatePreferences('user-1', { emailFrequency: 'daily-digest' });
+      expect(service.shouldSendNotification('user-1', 'order-confirmation', 'email')).toBe(false);
+    });
+
+    it('should allow non-email channels regardless of email preferences', () => {
+      service.updatePreferences('user-1', { emailEnabled: false });
