+      expect(service.shouldSendNotification('user-1', 'order-confirmation', 'sms' as 'email')).toBe(true);
+    });
+  });
+
+  describe('clearAll', () => {
+    it('should clear all stored preferences', () => {
+      service.updatePreferences('user-1', { emailEnabled: false });
+      service.updatePreferences('user-2', { emailEnabled: false });
+      service.clearAll();
+      expect(service.getPreferences('user-1').emailEnabled).toBe(true);
+      expect(service.getPreferences('user-2').emailEnabled).toBe(true);
+    });
+  });
+});
+
+describe('NotificationService with preferences', () => {
+  let eventBus: EventBus;
+  let notificationService: NotificationService;
+  let preferencesService: PreferencesService;
+
+  beforeEach(() => {
+    eventBus = new EventBus();
+    notificationService = new NotificationService(eventBus);
+    preferencesService = new PreferencesService();
+    notificationService.setPreferencesService(preferencesService);
+    resetNotificationIdCounter();
+  });
+
+  const orderCreatedEvent: OrderCreatedEvent = {
+    type: 'order:created',
+    order: {
+      id: 'order-1',
+      userId: 'user-1',
+      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
+      total: 10,
+      status: 'pending',
+      createdAt: new Date(),
+      updatedAt: new Date(),
+    },
+    user: {
+      id: 'user-1',
+      name: 'Alice',
+      email: 'alice@example.com',
+      role: 'member',
+      createdAt: new Date(),
+      updatedAt: new Date(),
+    },
+    timestamp: new Date(),
+  };
+
+  const userCreatedEvent: UserCreatedEvent = {
+    type: 'user:created',
+    user: {
+      id: 'user-1',
+      name: 'Alice',
+      email: 'alice@example.com',
+      role: 'member',
+      createdAt: new Date(),
+      updatedAt: new Date(),
+    },
+    timestamp: new Date(),
+  };
+
+  it('should send notification when preferences allow it', async () => {
+    await eventBus.emit(orderCreatedEvent);
+    expect(notificationService.getNotificationCount()).toBe(1);
+  });
+
+  it('should block notification when email is globally disabled', async () => {
+    preferencesService.updatePreferences('user-1', { emailEnabled: false });
+    await eventBus.emit(orderCreatedEvent);
+    expect(notificationService.getNotificationCount()).toBe(0);
+  });
+
+  it('should block notification for unsubscribed category', async () => {
+    preferencesService.updatePreferences('user-1', {
+      categorySubscriptions: { 'order-confirmation': false },
+    });
+    await eventBus.emit(orderCreatedEvent);
+    expect(notificationService.getNotificationCount()).toBe(0);
+  });
+
+  it('should allow other categories when one is unsubscribed', async () => {
+    preferencesService.updatePreferences('user-1', {
+      categorySubscriptions: { 'order-status-update': false },
+    });
+    // order-confirmation should still go through
+    await eventBus.emit(orderCreatedEvent);
+    expect(notificationService.getNotificationCount()).toBe(1);
+  });
+
+  it('should block notification when frequency is digest', async () => {
+    preferencesService.updatePreferences('user-1', { emailFrequency: 'weekly-digest' });
+    await eventBus.emit(orderCreatedEvent);
+    expect(notificationService.getNotificationCount()).toBe(0);
+  });
+
+  it('should send welcome email even with default preferences', async () => {
+    await eventBus.emit(userCreatedEvent);
+    expect(notificationService.getNotificationCount()).toBe(1);
