+    expect(notifications[0]?.subject).toBe('Welcome to TaskFlow Pro');
+  });
+
+  it('should block welcome email when user-welcome category is unsubscribed', async () => {
+    preferencesService.updatePreferences('user-1', {
+      categorySubscriptions: { 'user-welcome': false },
+    });
+    await eventBus.emit(userCreatedEvent);
+    expect(notificationService.getNotificationCount()).toBe(0);
+  });
+});

