/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications.
 * Currently designed around email (the only channel), but
 * structured to accommodate future channels.
 */

import type { NotificationType } from './notification.js';

/**
 * How frequently email notifications should be delivered.
 * 'immediate' sends each notification as it occurs.
 * Digest modes are defined for future batching support.
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'weekly-digest';

/**
 * A time-of-day window during which notifications should not be sent.
 * Hours are in 24-hour format (0-23).
 */
export interface QuietHours {
  start: number;
  end: number;
}

/**
 * Full notification preferences for a user.
 */
export interface UserNotificationPreferences {
  userId: string;

  /** Master switch for all email notifications. */
  emailEnabled: boolean;

  /** Per-category subscription flags. Missing keys default to enabled. */
  categorySubscriptions: Partial<Record<NotificationType, boolean>>;

  /** Email delivery frequency. */
  emailFrequency: EmailFrequency;

  /** Optional quiet hours window. */
  quietHours?: QuietHours;

  updatedAt: Date;
}

/**
 * Input for creating or updating preferences.
 * All fields except userId are optional — unset fields keep defaults.
 */
export interface UpdatePreferencesInput {
  emailEnabled?: boolean;
  categorySubscriptions?: Partial<Record<NotificationType, boolean>>;
  emailFrequency?: EmailFrequency;
  quietHours?: QuietHours | null;
}

/**
 * Returns default preferences for a user (all notifications enabled, immediate delivery).
 */
export function getDefaultPreferences(userId: string): UserNotificationPreferences {
  return {
    userId,
    emailEnabled: true,
    categorySubscriptions: {},
    emailFrequency: 'immediate',
    updatedAt: new Date(),
  };
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for notification preferences and a
 * shouldSendNotification() check consumed by NotificationService.
 *
 * Storage is in-memory, consistent with the repository pattern
 * used elsewhere in the codebase.
 */

import type { NotificationType } from '../models/notification.js';
import type {
  UserNotificationPreferences,
  UpdatePreferencesInput,
} from '../models/user-preferences.js';
import { getDefaultPreferences } from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

export class PreferencesService {
  private logger = new Logger('PreferencesService');
  private preferences: Map<string, UserNotificationPreferences> = new Map();

  /**
   * Get preferences for a user. Returns defaults if none have been set.
   */
  getPreferences(userId: string): UserNotificationPreferences {
    return this.preferences.get(userId) ?? getDefaultPreferences(userId);
  }

  /**
   * Update preferences for a user. Creates preferences with defaults
   * if the user has none, then applies the partial update.
   */
  updatePreferences(userId: string, input: UpdatePreferencesInput): UserNotificationPreferences {
    const current = this.getPreferences(userId);

    const updated: UserNotificationPreferences = {
      ...current,
      userId,
      updatedAt: new Date(),
    };

    if (input.emailEnabled !== undefined) {
      updated.emailEnabled = input.emailEnabled;
    }

    if (input.categorySubscriptions !== undefined) {
      updated.categorySubscriptions = {
        ...current.categorySubscriptions,
        ...input.categorySubscriptions,
      };
    }

    if (input.emailFrequency !== undefined) {
      updated.emailFrequency = input.emailFrequency;
    }

    if (input.quietHours === null) {
      updated.quietHours = undefined;
    } else if (input.quietHours !== undefined) {
      updated.quietHours = input.quietHours;
    }

    this.preferences.set(userId, updated);
    this.logger.info(`Updated preferences for user ${userId}`);
    return updated;
  }

  /**
   * Delete stored preferences for a user, reverting them to defaults.
   */
  deletePreferences(userId: string): boolean {
    const deleted = this.preferences.delete(userId);
    if (deleted) {
      this.logger.info(`Deleted preferences for user ${userId}`);
    }
    return deleted;
  }

  /**
   * Determine whether a notification should be sent to a user.
   *
   * Checks:
   * 1. Global emailEnabled flag
   * 2. Per-category subscription (missing category = enabled)
   * 3. Email frequency (only 'immediate' sends right away)
   *
   * Returns true if the notification should be sent now.
   */
  shouldSendNotification(userId: string, type: NotificationType, channel: 'email'): boolean;
  shouldSendNotification(userId: string, type: NotificationType, channel: string): boolean {
    if (channel !== 'email') {
      // Only email preferences are implemented; allow other channels through
      return true;
    }

    const prefs = this.getPreferences(userId);

    if (!prefs.emailEnabled) {
      this.logger.info(`Notification blocked for ${userId}: email disabled`);
      return false;
    }

    const categoryEnabled = prefs.categorySubscriptions[type];
    if (categoryEnabled === false) {
      this.logger.info(`Notification blocked for ${userId}: category '${type}' unsubscribed`);
      return false;
    }

    if (prefs.emailFrequency !== 'immediate') {
      this.logger.info(`Notification deferred for ${userId}: frequency is ${prefs.emailFrequency}`);
      return false;
    }

    return true;
  }

  /**
   * Clear all stored preferences (useful for testing).
   */
  clearAll(): void {
    this.preferences.clear();
  }
}

